class Ledger:
    def __init__(self):
        self.balance = 0
        self.history = []

    def deposit(self, amt):
        if amt < 0:
            raise ValueError('negative')
        self.balance += amt
        self.history.append(('deposit', amt))

    def withdraw(self, amt):
        self.balance -= amt
        self.history.append(('withdraw', amt))

    def balance_after(self, n):
        b = 0
        for op, amt in self.history[:n - 1]:
            b += amt if op == 'deposit' else -amt
        return b

    def total_deposited(self):
        return sum(amt for op, amt in self.history)

