class Matrix:
    def __init__(self, rows, cols, fill=0):
        self.rows = rows
        self.cols = cols
        self._rows = [[fill] * cols for _ in range(rows)]

    def get(self, r, c):
        return self._rows[r][c]

    def set(self, r, c, v):
        self._rows[r][c] = v

    def row_sum(self, r):
        return sum(self._rows[r])

    def col_sum(self, c):
        return sum(self._rows[r][c] for r in range(self.rows))

    def transpose(self):
        m = Matrix(self.cols, self.rows)
        for r in range(self.rows):
            for c in range(self.cols):
                m.set(c, r, self.get(r, c))
        return m
